const HowItWorks = () => (
    <section style={{ padding: '80px 20px', background: '#0c0a09' }}>
        <h2 style={{ textAlign: 'center', color: '#fff', marginBottom: '50px' }}>3 Langkah Mudah</h2>
        <div style={{ display: 'flex', gap: '40px', justifyContent: 'center', flexWrap: 'wrap' }}>
            {['Daftar Akun', 'Cari Pekerjaan', 'Kirim Lamaran'].map((step, i) => (
                <div key={i} style={{ width: '250px', textAlign: 'center', color: '#a3a3a3' }}>
                    <div style={{ width: '60px', height: '60px', background: '#ea580c', borderRadius: '50%', margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 'bold' }}>{i + 1}</div>
                    <h3>{step}</h3>
                </div>
            ))}
        </div>
    </section>
);
export default HowItWorks;
